Implemeation of several step.

# 1. Simple construction
```
function Promise1(fn) {
  var doneCallback;
  this.then = function (done) {
    doneCallback = done;
    return this;
  }
  function resolve(value) {
    doneCallback(value);
  }
  fn(resolve);
}
```

# 2. Add chain support, async callback
```
function Promise2(fn) {
  var doneList = [];
  this.then = function (done, fail) {
    doneList.push(done);
    return this;
  }
  function resolve(value) {
    setTimeout(function () {
      doneList.forEach(function (fulfill) {
        fulfill(value);
      });
    }, 0);
  }
  fn(resolve);
}
```

# 3. Addition state judgment
```
function Promise3(fn) {
  var state = 'pending';
  var doneList = [];
  this.then = function (done) {
    switch (state) {
      case "pending":
        doneList.push(done);
        return this;
        break;
      case 'fulfilled':
        done();
        return this;
        break;
    }
  };
  function resolve(value) {
    setTimeout(function () {
      state = "fulfilled";
      doneList.forEach(function (fulfill) {
        fulfill(value);
      });
    }, 0);
  };
  fn(resolve);
}
```

# 4. Plus result transfer.
```
function Promise4(fn) {
  var state = 'pending';
  var doneList = [];
  this.then = function (done) {
    switch (state) {
      case "pending":
        doneList.push(done);
        return this;
        break;
      case 'fulfilled':
        done();
        return this;
        break;
    }
  };

  function resolve(newValue) {
    setTimeout(function () {
      state = "fulfilled";
      let value = newValue;
      doneList.forEach((fulfill) => {
        value = fulfill(value);
      });
    }, 0);
  };
  fn(resolve);
}
```

# 5. Support serial.
```
function Promise5(fn) {
  var state = 'pending';
  var doneList = [];
  this.then = function (done) {
    switch (state) {
      case "pending":
        doneList.push(done);
        return this;
        break;
      case 'fulfilled':
        done();
        return this;
        break;
    }
  };

  function resolve(newValue) {
    setTimeout(function () {
      state = "fulfilled";
      let value = newValue;
      for (var i = 0; i < doneList.length; i++) {
        var temp = doneList[i](value)
        if (temp instanceof Promise5) {
          var newP = temp;
          for (i++; i < doneList.length; i++) {
            newP.then(doneList[i]);
          }
        } else {
          value = temp;
        }
      }
    }, 0);
  };
  fn(resolve);
}
```

# 6. Join reject support.

```
function Promise6(fn) {
  var state = 'pending';
  var doneList = [];
  var failList = [];
  this.then = function (done, fail) {
    switch (state) {
      case "pending":
        doneList.push(done);
        failList.push(fail || null);
        return this;
        break;
      case 'fulfilled':
        done();
        return this;
        break;
      case 'rejected':
        fail();
        return this;
        break;
    }
  }
  function resolve(newValue) {
    setTimeout(function () {
      state = "fulfilled";
      var value = newValue;
      for (var i = 0; i < doneList.length; i++) {
        var temp = doneList[i](value);
        if (temp instanceof Promise) {
          var newP = temp;
          for (i++; i < doneList.length; i++) {
            newP.then(doneList[i], failList[i]);
          }
        } else {
          value = temp;
        }
      }
    }, 0);
  }
  function reject(newValue) {
    setTimeout(function () {
      state = "rejected";
      var value = newValue;
      var tempRe = failList[0](value);
      if (tempRe instanceof Promise) {
        var newP = tempRe;
        for (i = 1; i < doneList.length; i++) {
          newP.then(doneList[i], failList[i]);
        }
      } else {
        value = tempRe;
        doneList.shift();
        failList.shift();
        resolve(value);
      }
    }, 0);
  }
  fn(resolve, reject);
}

```

# The method is realized.
```
const promise = new Promise6((resolve, reject) => {
  setTimeout(() => {
    resolve(111);
  })
});

promise
  .then((value) => {
    return new Promise((resolve) => {
      setTimeout(() => {
        console.log('p2拿到前面传入的值：' + value)
        resolve('p2的结果');
      }, 100);
    });
  }, (value) => {
    console.log(value); 
    return 'p then方法第一次错误的返回';
  })
  .then((value) => {
    console.log(value);
  })

```

